package terminal

import (
	"context"
	"fmt"
	"sync"
	"time"
)

// Detector scans for terminal sessions and emits lifecycle events.
type Detector struct {
	config DetectorConfig

	mu       sync.RWMutex
	running  bool
	ctx      context.Context
	cancel   context.CancelFunc

	sessions map[string]*DetectedTerminal
	events   chan TerminalEvent

	adapters []TerminalAdapter
}

// DetectorConfig holds detector configuration.
type DetectorConfig struct {
	PollInterval time.Duration
	MaxRetries   int
}

// DefaultDetectorConfig returns default detector configuration.
func DefaultDetectorConfig() DetectorConfig {
	return DetectorConfig{
		PollInterval: 2 * time.Second,
		MaxRetries:   3,
	}
}

// NewDetector creates a new terminal detector.
func NewDetector(config DetectorConfig, adapters ...TerminalAdapter) *Detector {
	ctx, cancel := context.WithCancel(context.Background())

	return &Detector{
		config:   config,
		ctx:      ctx,
		cancel:   cancel,
		sessions: make(map[string]*DetectedTerminal),
		events:   make(chan TerminalEvent, 100),
		adapters: adapters,
	}
}

// Start begins the detection loop.
func (d *Detector) Start() error {
	d.mu.Lock()
	defer d.mu.Unlock()

	if d.running {
		return nil
	}

	d.running = true
	go d.runDetectionLoop()

	return nil
}

// Stop halts the detection loop.
func (d *Detector) Stop() error {
	d.mu.Lock()
	defer d.mu.Unlock()

	if !d.running {
		return nil
	}

	d.running = false
	d.cancel()

	return nil
}

// IsRunning returns whether the detector is active.
func (d *Detector) IsRunning() bool {
	d.mu.RLock()
	defer d.mu.RUnlock()
	return d.running
}

// GetSessions returns a copy of the current session map.
func (d *Detector) GetSessions() map[string]*DetectedTerminal {
	d.mu.RLock()
	defer d.mu.RUnlock()

	copy := make(map[string]*DetectedTerminal, len(d.sessions))
	for k, v := range d.sessions {
		copy[k] = v
	}
	return copy
}

// Events returns the event channel for subscription.
func (d *Detector) Events() <-chan TerminalEvent {
	return d.events
}

// runDetectionLoop polls adapters and emits events.
func (d *Detector) runDetectionLoop() {
	ticker := time.NewTicker(d.config.PollInterval)
	defer ticker.Stop()

	for {
		select {
		case <-d.ctx.Done():
			return
		case <-ticker.C:
			d.pollAdapters()
		}
	}
}

// pollAdapters queries all adapters for sessions.
func (d *Detector) pollAdapters() {
	for _, adapter := range d.adapters {
		if !adapter.Available(d.ctx) {
			continue
		}

		sessions, err := adapter.ListSessions(d.ctx)
		if err != nil {
			continue
		}

		d.updateSessions(sessions)
	}
}

// updateSessions updates session cache and emits events.
func (d *Detector) updateSessions(sessions []DetectedTerminal) {
	d.mu.Lock()
	defer d.mu.Unlock()

	currentIDs := make(map[string]bool)

	for _, s := range sessions {
		currentIDs[s.ID] = true

		if _, exists := d.sessions[s.ID]; !exists {
			d.sessions[s.ID] = &s
			d.emitEvent(TerminalEvent{
				Type:       EventSessionCreated,
				TerminalID: s.ID,
				Timestamp:  time.Now(),
				Data:       s.Name,
			})
		} else {
			existing := d.sessions[s.ID]
			if existing.Command != s.Command || existing.WorkingDir != s.WorkingDir {
				d.sessions[s.ID] = &s
				d.emitEvent(TerminalEvent{
					Type:       EventActivityChange,
					TerminalID: s.ID,
					Timestamp:  time.Now(),
					Data:       fmt.Sprintf("Command: %s, Dir: %s", s.Command, s.WorkingDir),
				})
			}
		}
	}

	for id := range d.sessions {
		if !currentIDs[id] {
			delete(d.sessions, id)
			d.emitEvent(TerminalEvent{
				Type:       EventSessionClosed,
				TerminalID: id,
				Timestamp:  time.Now(),
			})
		}
	}
}

// emitEvent sends an event to subscribers.
func (d *Detector) emitEvent(event TerminalEvent) {
	select {
	case d.events <- event:
	default:
	}
}

// AddAdapter registers a new terminal adapter.
func (d *Detector) AddAdapter(adapter TerminalAdapter) {
	d.mu.Lock()
	defer d.mu.Unlock()
	d.adapters = append(d.adapters, adapter)
}

// SessionCount returns the number of detected sessions.
func (d *Detector) SessionCount() int {
	d.mu.RLock()
	defer d.mu.RUnlock()
	return len(d.sessions)
}

package terminal

import (
	"context"
	"testing"
	"time"
)

// MockAdapter for testing
type MockAdapter struct {
	sessions []DetectedTerminal
	connected bool
}

func (m *MockAdapter) Name() string { return "mock" }
func (m *MockAdapter) Available(ctx context.Context) bool { return true }
func (m *MockAdapter) Connect(ctx context.Context) error { m.connected = true; return nil }
func (m *MockAdapter) Disconnect(ctx context.Context) error { m.connected = false; return nil }
func (m *MockAdapter) IsConnected() bool { return m.connected }
func (m *MockAdapter) ListSessions(ctx context.Context) ([]DetectedTerminal, error) { return m.sessions, nil }
func (m *MockAdapter) Capture(ctx context.Context, id string) (string, error) { return "", nil }
func (m *MockAdapter) Subscribe(ctx context.Context, id string) (<-chan TerminalEvent, error) { return nil, nil }
func (m *MockAdapter) GetDimensions(ctx context.Context, id string) (int, int, error) { return 0, 0, nil }

func TestNewDetector(t *testing.T) {
	config := DefaultDetectorConfig()
	adapter := &MockAdapter{}
	detector := NewDetector(config, adapter)

	if detector == nil {
		t.Fatal("Expected detector to be created")
	}

	if detector.IsRunning() {
		t.Error("Expected detector to be stopped initially")
	}

	if detector.SessionCount() != 0 {
		t.Errorf("Expected 0 sessions, got %d", detector.SessionCount())
	}
}

func TestDetectorStartStop(t *testing.T) {
	config := DefaultDetectorConfig()
	detector := NewDetector(config)

	if err := detector.Start(); err != nil {
		t.Fatalf("Start failed: %v", err)
	}

	if !detector.IsRunning() {
		t.Error("Expected detector to be running")
	}

	// Start again should be no-op
	if err := detector.Start(); err != nil {
		t.Errorf("Second Start should succeed: %v", err)
	}

	if err := detector.Stop(); err != nil {
		t.Fatalf("Stop failed: %v", err)
	}

	if detector.IsRunning() {
		t.Error("Expected detector to be stopped")
	}
}

func TestDetectorGetSessions(t *testing.T) {
	config := DefaultDetectorConfig()
	detector := NewDetector(config)

	sessions := detector.GetSessions()
	if len(sessions) != 0 {
		t.Errorf("Expected empty sessions, got %d", len(sessions))
	}
}

func TestDetectorEvents(t *testing.T) {
	config := DefaultDetectorConfig()
	detector := NewDetector(config)

	events := detector.Events()
	if events == nil {
		t.Fatal("Expected events channel")
	}
}

func TestDetectorWithMockAdapter(t *testing.T) {
	config := DetectorConfig{PollInterval: 100 * time.Millisecond}
	adapter := &MockAdapter{
		sessions: []DetectedTerminal{
			{ID: "s1", Name: "Session 1", IsActive: true},
			{ID: "s2", Name: "Session 2", IsActive: true},
		},
	}

	detector := NewDetector(config, adapter)

	if err := detector.Start(); err != nil {
		t.Fatalf("Start failed: %v", err)
	}

	// Wait for polling
	time.Sleep(150 * time.Millisecond)

	sessions := detector.GetSessions()
	if len(sessions) != 2 {
		t.Logf("Expected 2 sessions after polling, got %d (may be timing)", len(sessions))
	}

	if err := detector.Stop(); err != nil {
		t.Fatalf("Stop failed: %v", err)
	}
}

func TestDetectorEventEmission(t *testing.T) {
	config := DetectorConfig{PollInterval: 50 * time.Millisecond}
	adapter := &MockAdapter{
		sessions: []DetectedTerminal{
			{ID: "new-session", Name: "New", IsActive: true},
		},
	}

	detector := NewDetector(config, adapter)

	if err := detector.Start(); err != nil {
		t.Fatalf("Start failed: %v", err)
	}
	defer detector.Stop()

	// Wait for event
	select {
	case event := <-detector.Events():
		t.Logf("Received event: %s for %s", event.Type, event.TerminalID)
	case <-time.After(200 * time.Millisecond):
		t.Log("No event received (may be expected with mock)")
	}
}

func TestDefaultDetectorConfig(t *testing.T) {
	config := DefaultDetectorConfig()

	if config.PollInterval != 2*time.Second {
		t.Errorf("Expected PollInterval 2s, got %v", config.PollInterval)
	}

	if config.MaxRetries != 3 {
		t.Errorf("Expected MaxRetries 3, got %d", config.MaxRetries)
	}
}

func TestDetectorAddAdapter(t *testing.T) {
	config := DefaultDetectorConfig()
	detector := NewDetector(config)

	adapter := &MockAdapter{}
	detector.AddAdapter(adapter)

	// Should not panic
	if err := detector.Start(); err != nil {
		t.Fatalf("Start failed: %v", err)
	}
	detector.Stop()
}

package terminal

import (
	"context"
	"runtime"
	"sync"
	"time"

	"github.com/pairadmin/pairadmin/internal/terminal/macos"
	"github.com/pairadmin/pairadmin/internal/terminal/tmux"
)

// DetectorConfig holds configuration for the terminal detector
type DetectorConfig struct {
	PollInterval time.Duration
	Timeout      time.Duration
}

// DefaultDetectorConfig returns default detector configuration
func DefaultDetectorConfig() DetectorConfig {
	return DetectorConfig{
		PollInterval: 1 * time.Second,
		Timeout:      5 * time.Second,
	}
}

// TerminalAdapter is an interface for terminal adapters
type TerminalAdapter interface {
	Name() string
	Available(ctx context.Context) bool
	Detect(ctx context.Context) ([]Terminal, error)
	Subscribe(ctx context.Context, ch chan<- TerminalEvent) error
	Unsubscribe(ch chan<- TerminalEvent)
}

// Terminal represents a detected terminal session
type Terminal struct {
	ID         string
	Name       string
	Path       string
	PID        int
	WorkingDir string
}

// TerminalEvent represents an event from terminal detection
type TerminalEvent struct {
	Type      string // "connected", "disconnected"
	Terminal  Terminal
	Timestamp time.Time
}

// AdapterStatus holds status information for an adapter
 type AdapterStatus struct {
	Name      string
	Available bool
	Type      string // "multiplexer" or "native"
}

// Detector monitors terminal sessions
 type Detector struct {
	config   DetectorConfig
	adapters []TerminalAdapter
	events   chan TerminalEvent
	mu       sync.RWMutex
	started  bool
	stop     chan struct{}
}

// isMacOS checks if running on macOS
func isMacOS() bool {
	return runtime.GOOS == "darwin"
}

// isMacOSAdapterAvailable checks if macOS adapter is available (macOS + accessibility enabled)
func isMacOSAdapterAvailable() bool {
	if runtime.GOOS != "darwin" {
		return false
	}
	return macos.IsAccessibilityEnabled()
}

// NewDetector creates detector with auto-registered adapters
func NewDetector(config DetectorConfig) *Detector {
	var adapters []TerminalAdapter

	// Auto-register tmux adapter (always available if tmux installed)
	tmuxAdapter := tmux.NewAdapter(tmux.DefaultConfig())
	adapters = append(adapters, tmuxAdapter)

	// Auto-register macOS adapter if available
	if isMacOSAdapterAvailable() {
		macosAdapter := macos.NewAdapter(macos.DefaultConfig())
		adapters = append(adapters, macosAdapter)
	}

	return &Detector{
		config:   config,
		adapters: adapters,
		events:   make(chan TerminalEvent, 100),
		stop:     make(chan struct{}),
	}
}

// Start begins terminal detection
func (d *Detector) Start() error {
	d.mu.Lock()
	d.started = true
	d.mu.Unlock()

	go d.detectLoop()
	return nil
}

// Stop stops terminal detection
func (d *Detector) Stop() {
	d.mu.Lock()
	if d.started {
		d.started = false
		close(d.stop)
	}
	d.mu.Unlock()
}

// Events returns the channel for terminal events
func (d *Detector) Events() <-chan TerminalEvent {
	return d.events
}

// RequestAccessibilityPermission requests macOS accessibility permission
// Call this when detector starts and accessibility is not enabled
func (d *Detector) RequestAccessibilityPermission() bool {
	if runtime.GOOS != "darwin" {
		return false
	}
	return macos.RequestAccessibilityPermission()
}

// GetAdapterStatus returns status of each registered adapter
func (d *Detector) GetAdapterStatus() []AdapterStatus {
	d.mu.RLock()
	defer d.mu.RUnlock()

	var statuses []AdapterStatus
	for _, adapter := range d.adapters {
		statuses = append(statuses, AdapterStatus{
			Name:      adapter.Name(),
			Available: adapter.Available(context.Background()),
			Type:      getAdapterType(adapter),
		})
	}
	return statuses
}

// getAdapterType returns the type of adapter
func getAdapterType(adapter TerminalAdapter) string {
	switch adapter.Name() {
	case "tmux", "screen":
		return "multiplexer"
	case "macos", "linux", "windows":
		return "native"
	default:
		return "unknown"
	}
}

func (d *Detector) detectLoop() {
	ticker := time.NewTicker(d.config.PollInterval)
	defer ticker.Stop()

	for {
		select {
		case <-ticker.C:
			d.detect()
		case <-d.stop:
			return
		}
	}
}

func (d *Detector) detect() {
	d.mu.RLock()
	adapters := d.adapters
	d.mu.RUnlock()

	ctx, cancel := context.WithTimeout(context.Background(), d.config.Timeout)
	defer cancel()

	for _, adapter := range adapters {
		if !adapter.Available(ctx) {
			continue
		}

		terminals, err := adapter.Detect(ctx)
		if err != nil {
			continue
		}

		for _, terminal := range terminals {
			d.events <- TerminalEvent{
				Type:      "connected",
				Terminal:  terminal,
				Timestamp: time.Now(),
			}
		}
	}
}

package terminal

import (
	"runtime"
	"testing"
	"time"

	"github.com/pairadmin/pairadmin/internal/terminal/tmux"
)

func TestDetectorAutoRegistersTmux(t *testing.T) {
	det := NewDetector(DefaultDetectorConfig())
	statuses := det.GetAdapterStatus()

	// tmux should always be registered (availability checked separately)
	found := false
	for _, s := range statuses {
		if s.Name == "tmux" {
			found = true
			break
		}
	}
	if !found {
		t.Error("tmux adapter should be registered")
	}
}

func TestDetectorMacOSAdapter(t *testing.T) {
	det := NewDetector(DefaultDetectorConfig())
	statuses := det.GetAdapterStatus()

	// Check macOS adapter registration based on platform
	found := false
	for _, s := range statuses {
		if s.Name == "macos" {
			found = true
			if runtime.GOOS != "darwin" {
				t.Error("macOS adapter should not be registered on non-macOS")
			}
			break
		}
	}

	if runtime.GOOS == "darwin" {
		// On macOS, adapter is registered (availability is separate check)
		t.Logf("macOS adapter registered: %v", found)
	} else {
		// On non-macOS, should not be registered
		if found {
			t.Error("macOS adapter should not be registered on non-macOS")
		}
	}
}

func TestDetectorCreatesWithDefaultConfig(t *testing.T) {
	det := NewDetector(DefaultDetectorConfig())

	if det == nil {
		t.Fatal("detector should not be nil")
	}

	config := det.(*Detector).config
	if config.PollInterval != 1*time.Second {
		t.Errorf("expected poll interval 1s, got %v", config.PollInterval)
	}
	if config.Timeout != 5*time.Second {
		t.Errorf("expected timeout 5s, got %v", config.Timeout)
	}
}

func TestDetectorGetAdapterStatus(t *testing.T) {
	det := NewDetector(DefaultDetectorConfig())
	statuses := det.GetAdapterStatus()

	// Should have at least tmux adapter
	if len(statuses) == 0 {
		t.Error("should have at least one adapter")
	}

	// Check that we have tmux adapter
	tmuxFound := false
	for _, s := range statuses {
		if s.Name == "tmux" {
			tmuxFound = true
			break
		}
	}

	if !tmuxFound {
		t.Error("tmux adapter should be present in status")
	}
}

func TestDetectorStartStop(t *testing.T) {
	det := NewDetector(DefaultDetectorConfig())

	// Should be able to start and stop
	err := det.Start()
	if err != nil {
		t.Errorf("start should not error: %v", err)
	}

det.Stop()
}
